// Map through ALL items coming from the previous node
return $input.all().map(item => {
    const rawText = item.json.output;

    try {
        // Parse the JSON string into a real JavaScript object
        const cleanJson = JSON.parse(rawText);

        // Return the parsed data alongside any other existing fields (like chat_id!)
        return {
            json: {
                ...item.json, // preserves chat_id, url, etc.
                ...cleanJson  // adds the newly parsed AI properties
            }
        };
    } catch (error) {
        // Fallback in case the AI format breaks on an item
        return { 
            json: { 
                ...item.json,
                error: "Failed to parse AI response", 
                raw: rawText 
            } 
        };
    }
});

return $input.all().map(item => {
    // 1. Traverse deeply to safely find Firecrawl's markdown string
    let text = "";
    if (item.json.data && item.json.data.markdown) {
        text = item.json.data.markdown;
    } else {
        text = item.json.markdown || item.json.text || "";
    }

    if (text) {
        // 2. Wipe out any Base64 encoded images/SVGs completely (Wipes the massive token-bloat blocks)
        text = text.replace(/data:image\/[^;]+;base64,[A-Za-z0-9+/=\s\n\r]+/g, '');

        // 3. Wipe out standard inline Markdown image formats: ![alt](url)
        text = text.replace(/!\[.*?\]\(.*?\)/g, '');

        // 4. Wipe out raw inline HTML graphics tags
        text = text.replace(/<svg[\s\S]*?<\/svg>/g, '');
        text = text.replace(/<img[\s\S]*?>/g, '');

        // 5. Clean up tracking blocks or messy remnants from broken tags
        text = text.replace(/data:image\/svg\+xml[\s\S]+?%3E%0A\)/g, '');
    }

    // 6. OVERWRITE the original paths entirely.
    // This way, your downstream Gemini prompt will naturally use the clean text without breaking.
    let updatedJson = { ...item.json };

    if (updatedJson.data && updatedJson.data.markdown) {
        updatedJson.data.markdown = text.trim();
    } else {
        updatedJson.markdown = text.trim();
    }

    return { json: updatedJson };
});

