// 1. Safe extraction of the output property from the incoming n8n item
let rawOutput = $input.first().json.output; 

let parsedData = {};

if (rawOutput) {
  try {
    if (typeof rawOutput === 'object') {
      parsedData = rawOutput;
    } else {
      let cleanString = rawOutput.trim();

      // Look for the first '{' and the last '}' to isolate the JSON block.
      // This completely ignores any ```json or trailing markdown characters.
      const firstBrace = cleanString.indexOf('{');
      const lastBrace = cleanString.lastIndexOf('}');

      if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
        cleanString = cleanString.substring(firstBrace, lastBrace + 1);
      }

      // Safely parse the clean, isolated JSON object
      parsedData = JSON.parse(cleanString);
    }
  } catch (error) {
    // Log the error natively inside your n8n execution console for debugging
    console.error("JSON parsing failed in Code Node:", error.message);
  }
}

// 2. Return the separated fields as distinct root-level keys
return {
  json: {
    for_matching: parsedData.resume_matching_payload || "Error parsing match data",
    for_notion: parsedData.interview_prep_payload || "Error parsing notion data"
  }
};

